array.string:
export PATH="$HOME/.local/bin:/usr/local/bin:/opt/homebrew/bin:$PATH";
cd /Users/tm/Projects/Claude/ResearchMan;
LOG=$HOME/Library/Logs/researchman-tuneup.log;
[ -f $LOG ] && [ $(stat -f%z $LOG) -gt 5242880 ] && mv $LOG $LOG.1;
node scripts/run-if-due.mjs --state .last-tuneup-run.txt --daily-at 8 --minute 30 --monthly-days 1,15 >> $LOG 2>&1 || exit 0;
# 収集3ジョブ(cc/tech/ideaseeds)と同じ排他ロックで直列化（git競合防止。最大45分待ち）。
# ロックが90分超残存していたらkill -9等の残骸とみなし奪取する
LOCK=/tmp/researchman-git.lock; waited=0;
while ! mkdir $LOCK 2>/dev/null; do
  if [ -d $LOCK ] && [ $(( $(date +%s) - $(stat -f %m $LOCK) )) -gt 5400 ]; then
    echo "staleロック奪取: $(date)" >> $LOG; rmdir $LOCK 2>/dev/null; continue;
  fi;
  sleep 30; waited=$((waited+30));
  [ $waited -ge 2700 ] && { echo "ロック取得タイムアウト: $(date)" >> $LOG; exit 0; };
done;
trap "rmdir $LOCK 2>/dev/null" EXIT;
echo "===== Tuneup start: $(date) =====" >> $LOG;
if node scripts/biweekly-tuneup.mjs >> $LOG 2>&1; then
  git add data/research-tuning.json data/idea-tuning.json data/x-radar-queries.json RESEARCH_PLAN.md >> $LOG 2>&1;
  if git diff --cached --quiet; then
    echo "変更なし（分析結果は現状維持 or スキップ）: $(date)" >> $LOG;
    node scripts/notify-line.mjs --text-file /tmp/researchman-tuneup-report.txt >> $LOG 2>&1;
  else
    git commit -m "chore: biweekly research tuning $(date '+%Y-%m-%d')" >> $LOG 2>&1;
    if git push >> $LOG 2>&1; then
      if node scripts/verify-deploy.mjs --skip-pages >> $LOG 2>&1; then
        echo "反映まで確認OK: $(date)" >> $LOG;
      else
        echo "push成功だが反映未確認（時間切れ）: $(date)" >> $LOG;
      fi;
      node scripts/notify-line.mjs --text-file /tmp/researchman-tuneup-report.txt >> $LOG 2>&1;
    else
      echo "push失敗（pre-push監査で中止の可能性）。コミットはローカル残存。要手動対応: $(date)" >> $LOG;
      node scripts/notify-line.mjs --text-file /tmp/researchman-tuneup-report.txt >> $LOG 2>&1;
    fi;
  fi;
else
  echo "チューンアップエラー終了: $(date)" >> $LOG;
  node scripts/run-if-due.mjs --state .last-tuneup-run.txt --mark >> $LOG 2>&1;
  node scripts/notify-line.mjs --text-file /tmp/researchman-tuneup-report.txt >> $LOG 2>&1;
fi;
echo "Tuneup completed: $(date)" >> $LOG
